let estado={usuario:null,paginaAtual:'dashboard',vendaAtual:[],filtroProduto:'',filtroCategoria:'',filtroMarca:'',paginaProduto:1,itensPorPagina:10};
function fmt(v){return'R$ '+parseFloat(v||0).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.');}
function fmtData(d){if(!d)return'';const p=d.split('-');return p[2]+'/'+p[1]+'/'+p[0];}
function hoje(){return new Date().toISOString().split('T')[0];}
function salvar(){try{localStorage.setItem('stockpro_db',JSON.stringify(DB));}catch(e){}}
function carregar(){if(window._fbCarregar){window._fbCarregar().then(function(obj){if(obj&&obj.usuarios){DB.usuarios=obj.usuarios;DB.produtos=obj.produtos||DB.produtos;DB.vendas=obj.vendas||[];DB.movimentacoes=obj.movimentacoes||[];DB.caixa=obj.caixa||[];DB.proximoId=obj.proximoId||DB.proximoId;}telaLogin();});return;} try{const d=localStorage.getItem('stockpro_db');if(d){const obj=JSON.parse(d);if(obj&&obj.usuarios){DB.usuarios=obj.usuarios;DB.produtos=obj.produtos||DB.produtos;DB.vendas=obj.vendas||[];DB.movimentacoes=obj.movimentacoes||[];DB.caixa=obj.caixa||[];DB.proximoId=obj.proximoId||DB.proximoId;}}}catch(e){}telaLogin();}function render(html){document.getElementById('app').innerHTML=html;}
function showToast(msg,tipo='success'){const t=document.createElement('div');t.style.cssText='position:fixed;top:20px;right:20px;padding:12px 20px;border-radius:8px;color:#fff;font-size:14px;z-index:9999;box-shadow:0 4px 12px rgba(0,0,0,.2);'+(tipo==='success'?'background:#16a34a':'background:#dc2626');t.textContent=msg;document.body.appendChild(t);setTimeout(()=>t.remove(),3000);}
function telaLogin(){render('<div class="login-container"><div class="login-box"><div class="login-logo"><span class="logo-icon">📦</span><h1>StockPro</h1><p>v2.0 - Sistema de Gestao Completo</p></div><div id="login-alert"></div><div class="form-group"><label class="form-label">Usuario</label><input class="form-control" id="l-user" placeholder="Digite seu usuario" value="maria"/></div><div class="form-group"><label class="form-label">Senha</label><input class="form-control" type="password" id="l-senha" placeholder="Digite sua senha"/></div><button class="btn btn-primary" style="width:100%;padding:12px;font-size:15px;" onclick="fazerLogin()">Entrar</button><p class="login-hint">maria/1234 (gestor) | joao/1234 | ana/1234</p></div></div>');document.getElementById('l-senha').addEventListener('keydown',e=>{if(e.key==='Enter')fazerLogin();});}
function fazerLogin(){const u=document.getElementById('l-user').value.trim();const s=document.getElementById('l-senha').value;const usr=DB.usuarios.find(x=>x.usuario===u&&x.senha===s&&x.ativo);if(!usr){document.getElementById('login-alert').innerHTML='<div class="alert alert-danger">Usuario ou senha invalidos!</div>';return;}estado.usuario=usr;renderApp();}
function renderApp(){const u=estado.usuario;const isGestor=u.perfil==='gestor';const navItems=[{id:'dashboard',icon:'🏠',label:'Dashboard'},{id:'catalogo',icon:'📖',label:'Catalogo'},{id:'estoque',icon:'📦',label:'Estoque'},{id:'caixa',icon:'💰',label:'Caixa/Vendas'},{id:'relatorios',icon:'📊',label:'Relatorios'},...(isGestor?[{id:'usuarios',icon:'👥',label:'Usuarios'},{id:'configuracoes',icon:'⚙️',label:'Configuracoes'}]:[])];const nav=navItems.map(n=>`<div class="nav-item${estado.paginaAtual===n.id?' active':''}" onclick="navegar('${n.id}')"><span class="nav-icon">${n.icon}</span>${n.label}</div>`).join('');render(`<div class="sidebar" id="sidebar"><div class="sidebar-logo"><span class="logo-icon">📦</span><div><div class="logo-text">StockPro</div><div class="logo-sub">v2.0</div></div></div><nav class="sidebar-nav">${nav}</nav><div class="sidebar-footer">© 2025 StockPro</div></div><div class="main-content"><div class="topbar"><div style="display:flex;align-items:center;gap:12px"><div class="hamburger" onclick="toggleSidebar()"><span></span><span></span><span></span></div><div class="topbar-title" id="topbar-title">Dashboard</div></div><div class="topbar-right"><div class="user-badge"><div class="user-avatar">${u.nome.charAt(0)}</div><div><div style="font-weight:600">${u.nome}</div><div style="font-size:11px;color:#64748b">${u.perfil}</div></div></div><button class="btn btn-outline btn-sm" onclick="fazerLogout()">🚪 Sair</button></div></div><div class="content-area" id="content-area"></div></div>`);renderPagina();}
function toggleSidebar(){document.getElementById('sidebar').classList.toggle('open');}
function fazerLogout(){estado.usuario=null;estado.paginaAtual='dashboard';estado.vendaAtual=[];telaLogin();}
function navegar(p){estado.paginaAtual=p;const titles={dashboard:'Dashboard',catalogo:'Catalogo de Produtos',estoque:'Estoque',caixa:'Caixa / Vendas',relatorios:'Relatorios',usuarios:'Usuarios',configuracoes:'Configuracoes'};document.getElementById('topbar-title').textContent=titles[p]||p;document.querySelectorAll('.nav-item').forEach(el=>{el.classList.remove('active');if(el.getAttribute('onclick')===`navegar('${p}')`)el.classList.add('active');});renderPagina();if(window.innerWidth<=768)document.getElementById('sidebar').classList.remove('open');}
function renderPagina(){const p=estado.paginaAtual;const el=document.getElementById('content-area');if(!el)return;if(p==='dashboard')el.innerHTML=renderDashboard();else if(p==='catalogo')el.innerHTML=renderCatalogo();else if(p==='estoque')el.innerHTML=renderEstoque();else if(p==='caixa')el.innerHTML=renderCaixa();else if(p==='relatorios')el.innerHTML=renderRelatorios();else if(p==='usuarios')el.innerHTML=renderUsuarios();else if(p==='configuracoes')el.innerHTML=renderConfiguracoes();}
function renderDashboard(){const u=estado.usuario;const isGestor=u.perfil==='gestor';const totalProd=DB.produtos.filter(p=>p.ativo).length;const prodBaixo=DB.produtos.filter(p=>p.ativo&&p.estoqueAtual<=p.estoqueMinimo);const vendasHoje=DB.vendas.filter(v=>v.data===hoje());const minhasVendasHoje=vendasHoje.filter(v=>v.usuario===u.nome);const meuFatHoje=minhasVendasHoje.reduce((a,v)=>a+v.total,0);const totalFatHoje=vendasHoje.reduce((a,v)=>a+v.total,0);const minhasVendasTotal=DB.vendas.filter(v=>v.usuario===u.nome);const meuFatTotal=minhasVendasTotal.reduce((a,v)=>a+v.total,0);if(isGestor){const totalCusto=DB.vendas.reduce((a,v)=>a+v.itens.reduce((b,i)=>b+(i.custo*i.qtd),0),0);const lucroTotal=DB.vendas.reduce((a,v)=>a+v.total,0)-totalCusto;const fatTotal=DB.vendas.reduce((a,v)=>a+v.total,0);const rankFunc=DB.usuarios.filter(x=>x.ativo).map(usr=>{const vs=DB.vendas.filter(v=>v.usuario===usr.nome);const fat=vs.reduce((a,v)=>a+v.total,0);return{nome:usr.nome,perfil:usr.perfil,qtd:vs.length,fat};}).sort((a,b)=>b.fat-a.fat);return`<div class="grid-4" style="margin-bottom:20px"><div class="stat-card"><div class="stat-icon" style="background:#dbeafe">📦</div><div class="stat-info"><div class="stat-value">${totalProd}</div><div class="stat-label">Produtos Ativos</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#dcfce7">💰</div><div class="stat-info"><div class="stat-value">${fmt(totalFatHoje)}</div><div class="stat-label">Faturamento Hoje</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#fef3c7">💵</div><div class="stat-info"><div class="stat-value">${fmt(fatTotal)}</div><div class="stat-label">Faturamento Total</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#f0fdf4">📈</div><div class="stat-info"><div class="stat-value" style="color:#16a34a">${fmt(lucroTotal)}</div><div class="stat-label">Lucro Total</div></div></div></div><div class="grid-2" style="margin-bottom:20px"><div class="stat-card"><div class="stat-icon" style="background:#fef3c7">📝</div><div class="stat-info"><div class="stat-value">${vendasHoje.length}</div><div class="stat-label">Vendas Hoje (total)</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#fee2e2">⚠️</div><div class="stat-info"><div class="stat-value estoque-low">${prodBaixo.length}</div><div class="stat-label">Alertas Estoque Baixo</div></div></div></div><div class="grid-2"><div class="card"><div class="card-title">🏆 Ranking de Faturamento por Funcionario</div>${rankFunc.map((r,i)=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid #f1f5f9"><div style="display:flex;align-items:center;gap:10px"><div style="width:28px;height:28px;border-radius:50%;background:${i===0?'#fbbf24':i===1?'#94a3b8':'#d97706'};color:#fff;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700">${i+1}</div><div><div style="font-weight:600;font-size:13px">${r.nome}</div><div style="font-size:11px;color:#64748b">${r.perfil} - ${r.qtd} venda(s)</div></div></div><div style="font-weight:700;color:#16a34a">${fmt(r.fat)}</div></div>`).join('')||'<p style="color:#64748b;font-size:13px">Sem vendas registradas</p>'}</div><div class="card"><div class="card-title">⚠️ Alertas de Estoque</div>${prodBaixo.length?prodBaixo.map(p=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f1f5f9"><div><div style="font-weight:600;font-size:13px">${p.nome}</div><div style="font-size:12px;color:#64748b">${p.categoria}</div></div><span class="badge badge-danger">${p.estoqueAtual} un</span></div>`).join(''):'<p style="color:#16a34a;font-size:13px">✅ Todos com estoque adequado</p>'}</div></div>`;}
return`<div class="grid-2" style="margin-bottom:20px"><div class="stat-card"><div class="stat-icon" style="background:#dbeafe">📝</div><div class="stat-info"><div class="stat-value">${minhasVendasHoje.length}</div><div class="stat-label">Minhas Vendas Hoje</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#dcfce7">💰</div><div class="stat-info"><div class="stat-value">${fmt(meuFatHoje)}</div><div class="stat-label">Meu Faturamento Hoje</div></div></div></div><div class="grid-2" style="margin-bottom:20px"><div class="stat-card"><div class="stat-icon" style="background:#fef3c7">💵</div><div class="stat-info"><div class="stat-value">${fmt(meuFatTotal)}</div><div class="stat-label">Meu Faturamento Total</div></div></div><div class="stat-card"><div class="stat-icon" style="background:#fee2e2">⚠️</div><div class="stat-info"><div class="stat-value estoque-low">${prodBaixo.length}</div><div class="stat-label">Alertas Estoque Baixo</div></div></div></div><div class="card"><div class="card-title">📈 Minhas Ultimas Vendas</div>${minhasVendasTotal.slice(-5).reverse().map(v=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f1f5f9"><div><div style="font-weight:600;font-size:13px">Venda #${v.id}</div><div style="font-size:12px;color:#64748b">${fmtData(v.data)} | ${v.itens.length} item(s) | ${v.formaPagamento}</div></div><div style="font-weight:700;color:#16a34a">${fmt(v.total)}</div></div>`).join('')||'<p style="color:#64748b;font-size:13px">Nenhuma venda realizada ainda</p>'}</div>`;}
function renderCatalogo(){const cats=[...new Set(DB.produtos.map(p=>p.marca).filter(Boolean))];return`<div style="margin-bottom:20px"><h2 style="font-size:18px;font-weight:700">📖 Catalogo de Produtos</h2><p style="font-size:13px;color:#64748b;margin-top:4px">Descritivo completo dos produtos disponíveis</p></div>${cats.map(cat=>`<div class="card" style="margin-bottom:20px"><div class="card-title" style="font-size:15px;border-bottom:2px solid #e2e8f0;padding-bottom:12px;margin-bottom:16px">🏷️ ${cat}</div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:16px">${DB.produtos.filter(p=>p.marca===cat&&p.ativo).map(p=>`<div style="background:#f8fafc;border-radius:12px;padding:16px;border:1px solid #e2e8f0"><div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:10px"><div><div style="font-weight:700;font-size:15px;color:#1e293b">${p.nome}</div><div style="font-size:11px;color:#64748b;margin-top:2px">Cod: ${p.codigo}</div></div><div style="text-align:right"><div style="font-size:18px;font-weight:800;color:#2563eb">${fmt(p.precoVenda)}</div><span class="badge ${p.estoqueAtual>p.estoqueMinimo?'badge-success':'badge-danger'}" style="font-size:10px">${p.estoqueAtual} em estoque</span></div></div><div style="font-size:12px;color:#475569;margin-bottom:8px;line-height:1.5"><strong>Descricao:</strong> ${p.descricao}</div><div style="background:#ecfdf5;border-radius:8px;padding:8px;margin-bottom:8px"><div style="font-size:11px;font-weight:700;color:#16a34a;margin-bottom:4px">✨ BENEFICIOS</div><div style="font-size:12px;color:#166534;line-height:1.4">${p.beneficios}</div></div>${p.observacoes?`<div style="background:#fffbeb;border-radius:8px;padding:8px;margin-bottom:8px"><div style="font-size:11px;font-weight:700;color:#d97706;margin-bottom:4px">⚠️ OBSERVACOES</div><div style="font-size:12px;color:#92400e;line-height:1.4">${p.observacoes}</div></div>`:''}<div style="display:flex;justify-content:space-between;font-size:11px;color:#94a3b8;margin-top:8px;padding-top:8px;border-top:1px solid #e2e8f0"><span>📊 Validade: ${fmtData(p.validade)}</span><span>💰 Custo: ${fmt(p.custo)}</span></div></div>`).join('')}</div></div>`).join('')||'<div class="card"><p style="color:#64748b">Nenhum produto ativo no catalogo.</p></div>'}`;}
function renderEstoque(){const isGestor=estado.usuario.perfil==='gestor';const cats=[...new Set(DB.produtos.map(p=>p.categoria))];const marcas=[...new Set(DB.produtos.map(p=>p.marca).filter(Boolean))];const filtro=estado.filtroProduto.toLowerCase();const catFiltro=estado.filtroCategoria;const marcaFiltro=estado.filtroMarca;let prods=DB.produtos.filter(p=>(!filtro||(p.nome+p.codigo+p.categoria+(p.marca||'')).toLowerCase().includes(filtro))&&(!catFiltro||p.categoria===catFiltro)&&(!marcaFiltro||p.marca===marcaFiltro));const total=prods.length;const paginas=Math.ceil(total/estado.itensPorPagina);const inicio=(estado.paginaProduto-1)*estado.itensPorPagina;const prodsPage=prods.slice(inicio,inicio+estado.itensPorPagina);const paginacao=paginas>1?`<div class="pagination">${Array.from({length:paginas},(_,i)=>`<button class="page-btn${estado.paginaProduto===i+1?' active':''}" onclick="irPagina(${i+1})">${i+1}</button>`).join('')}</div>`:'';return`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">Estoque de Produtos</h2>${isGestor?'<button class="btn btn-primary" onclick="abrirModalProduto()">+ Novo Produto</button>':''}</div><div class="card"><div class="search-bar"><input class="form-control" placeholder="Buscar produto..." value="${estado.filtroProduto}" oninput="filtrarProdutos(this.value)"/><select class="form-control" style="width:180px" onchange="filtrarCategoria(this.value)"><option value="">Todas Categorias</option>${cats.map(c=>`<option value="${c}"${estado.filtroCategoria===c?' selected':''}>${c}</option>`).join('')}</select><select class="form-control" style="width:180px" onchange="filtrarMarca(this.value)"><option value="">Todas Marcas</option>${marcas.map(m=>`<option value="${m}"${estado.filtroMarca===m?' selected':''}>${m}</option>`).join('')}</select></div><div class="table-container"><table class="table"><thead><tr><th>Codigo</th><th>Produto</th><th>Marca</th><th>Categoria</th><th>Preco</th><th>Custo</th><th>Estoque</th><th>Validade</th><th>Status</th>${isGestor?'<th>Acoes</th>':''}</tr></thead><tbody>${prodsPage.map(p=>{const baixo=p.estoqueAtual<=p.estoqueMinimo;return`<tr><td>${p.codigo}</td><td><div style="font-weight:600">${p.nome}</div><div style="font-size:11px;color:#64748b">${p.descricao.substring(0,50)}...</div></td><td><span class="tag" style="background:#fef3c7;color:#92400e">${p.marca||"-"}</span></td><td><span class="tag">${p.categoria}</span></td><td><strong>${fmt(p.precoVenda)}</strong></td><td style="font-size:12px;color:#64748b">${fmt(p.custo)}</td><td class="${baixo?'estoque-low':''}"><strong>${p.estoqueAtual}</strong> un${baixo?' ⚠️':''}<br/><span style="font-size:10px;color:#94a3b8">min: ${p.estoqueMinimo}</span></td><td style="font-size:12px">${fmtData(p.validade)}</td><td><span class="badge ${p.ativo?'badge-success':'badge-danger'}">${p.ativo?'Ativo':'Inativo'}</span></td>${isGestor?`<td style="white-space:nowrap"><button class="btn btn-outline btn-sm" onclick="editarProduto(${p.id})" style="margin-right:4px" title="Editar">✏️</button><button class="btn btn-outline btn-sm" onclick="movEstoque(${p.id})" style="margin-right:4px" title="Movimentacao">📦</button><button class="btn btn-danger btn-sm" onclick="removerProduto(${p.id})" title="Remover">🗑️</button></td>`:''}</tr>`;}).join('')}</tbody></table></div>${paginacao}<div style="font-size:12px;color:#64748b;margin-top:8px">${total} produto(s) encontrado(s)</div></div><div id="modal-produto" class="modal-overlay"></div><div id="modal-mov" class="modal-overlay"></div>`;}
function removerProduto(id){const p=DB.produtos.find(x=>x.id===id);if(!confirm(`Remover o produto "${p.nome}"? Esta acao nao pode ser desfeita.`))return;DB.produtos=DB.produtos.filter(x=>x.id!==id);salvar();renderPagina();showToast('Produto removido com sucesso!');}
function irPagina(p){estado.paginaProduto=p;renderPagina();}
function filtrarProdutos(v){estado.filtroProduto=v;estado.paginaProduto=1;renderPagina();}
function filtrarCategoria(v){estado.filtroCategoria=v;estado.paginaProduto=1;renderPagina();}
function abrirModalProduto(id){const p=id?DB.produtos.find(x=>x.id===id):null;const cats=['Suplementos','Aminoacidos','Vitaminas','Minerais','Proteinas','Outros'];const m=document.getElementById('modal-produto');m.innerHTML=`<div class="modal"><div class="modal-header"><h3 class="modal-title">${p?'Editar':'Novo'} Produto</h3><button class="modal-close" onclick="fecharModal('modal-produto')">&times;</button></div><div class="form-row"><div class="form-group"><label class="form-label">Codigo</label><input class="form-control" id="mp-codigo" value="${p?p.codigo:''}"/></div><div class="form-group"><label class="form-label">Nome *</label><input class="form-control" id="mp-nome" value="${p?p.nome:''}"/></div></div><div class="form-group"><label class="form-label">Marca</label><input class="form-control" id="mp-marca" value="${p?p.marca||'':''}" placeholder="Ex: Growth, Adaptogen..."/></div><div class="form-row"><div class="form-group"><label class="form-label">Categoria</label><select class="form-control" id="mp-cat">${cats.map(c=>`<option${p&&p.categoria===c?' selected':''}>${c}</option>`).join('')}</select></div><div class="form-group"><label class="form-label">Validade</label><input class="form-control" type="date" id="mp-val" value="${p?p.validade:''}"/></div></div><div class="form-group"><label class="form-label">Descricao</label><textarea class="form-control" id="mp-desc" rows="2">${p?p.descricao:''}</textarea></div><div class="form-group"><label class="form-label">Beneficios</label><textarea class="form-control" id="mp-ben" rows="2">${p?p.beneficios:''}</textarea></div><div class="form-group"><label class="form-label">Observacoes</label><input class="form-control" id="mp-obs" value="${p?p.observacoes:''}"/></div><div class="form-row"><div class="form-group"><label class="form-label">Custo (R$)</label><input class="form-control" type="number" step="0.01" id="mp-custo" value="${p?p.custo:''}"/></div><div class="form-group"><label class="form-label">Preco Venda (R$)</label><input class="form-control" type="number" step="0.01" id="mp-preco" value="${p?p.precoVenda:''}"/></div></div><div class="form-row"><div class="form-group"><label class="form-label">Estoque Atual</label><input class="form-control" type="number" id="mp-estq" value="${p?p.estoqueAtual:0}"/></div><div class="form-group"><label class="form-label">Estoque Minimo</label><input class="form-control" type="number" id="mp-min" value="${p?p.estoqueMinimo:5}"/></div></div><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn btn-outline" onclick="fecharModal('modal-produto')">Cancelar</button><button class="btn btn-primary" onclick="salvarProduto(${p?p.id:'null'})">Salvar</button></div></div>`;m.classList.add('open');}
function salvarProduto(id){const nome=document.getElementById('mp-nome').value.trim();if(!nome){showToast('Nome obrigatorio','danger');return;}const marca=(document.getElementById('mp-marca')||{}).value||'';const dados={codigo:document.getElementById('mp-codigo').value.trim()||'P'+String(DB.proximoId.produto).padStart(3,'0'),nome,categoria:document.getElementById('mp-cat').value,validade:document.getElementById('mp-val').value,descricao:document.getElementById('mp-desc').value,beneficios:document.getElementById('mp-ben').value,observacoes:document.getElementById('mp-obs').value,custo:parseFloat(document.getElementById('mp-custo').value)||0,precoVenda:parseFloat(document.getElementById('mp-preco').value)||0,estoqueAtual:parseInt(document.getElementById('mp-estq').value)||0,estoqueMinimo:parseInt(document.getElementById('mp-min').value)||5,marca:marca,ativo:true};if(id){const i=DB.produtos.findIndex(p=>p.id===id);DB.produtos[i]={...DB.produtos[i],...dados};}else{dados.id=DB.proximoId.produto++;DB.produtos.push(dados);}salvar();fecharModal('modal-produto');renderPagina();showToast('Produto salvo!');}
function editarProduto(id){abrirModalProduto(id);}
function movEstoque(id){const p=DB.produtos.find(x=>x.id===id);const m=document.getElementById('modal-mov');m.innerHTML=`<div class="modal"><div class="modal-header"><h3 class="modal-title">Movimentacao: ${p.nome}</h3><button class="modal-close" onclick="fecharModal('modal-mov')">&times;</button></div><p style="font-size:13px;color:#64748b;margin-bottom:16px">Estoque atual: <strong>${p.estoqueAtual}</strong> unidades</p><div class="form-row"><div class="form-group"><label class="form-label">Tipo</label><select class="form-control" id="mv-tipo"><option value="entrada">Entrada</option><option value="saida">Saida</option></select></div><div class="form-group"><label class="form-label">Quantidade</label><input class="form-control" type="number" id="mv-qtd" min="1" value="1"/></div></div><div class="form-group"><label class="form-label">Motivo</label><input class="form-control" id="mv-motivo" placeholder="Motivo da movimentacao"/></div><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn btn-outline" onclick="fecharModal('modal-mov')">Cancelar</button><button class="btn btn-primary" onclick="confirmarMov(${id})">Confirmar</button></div></div>`;m.classList.add('open');}
function confirmarMov(id){const tipo=document.getElementById('mv-tipo').value;const qtd=parseInt(document.getElementById('mv-qtd').value)||0;const motivo=document.getElementById('mv-motivo').value;const p=DB.produtos.find(x=>x.id===id);if(qtd<=0){showToast('Quantidade invalida','danger');return;}if(tipo==='saida'&&qtd>p.estoqueAtual){showToast('Estoque insuficiente','danger');return;}p.estoqueAtual+=tipo==='entrada'?qtd:-qtd;DB.movimentacoes.push({id:DB.proximoId.mov++,produtoId:id,tipo,quantidade:qtd,motivo,data:hoje(),usuario:estado.usuario.nome});salvar();fecharModal('modal-mov');renderPagina();showToast(`Movimentacao ok! Novo estoque: ${p.estoqueAtual}`);}
function fecharModal(id){const m=document.getElementById(id);if(m)m.classList.remove('open');}
function renderCaixa(){const total=estado.vendaAtual.reduce((a,i)=>a+(i.preco*i.qtd*(1-i.desconto/100)),0);const prods=DB.produtos.filter(p=>p.ativo&&p.estoqueAtual>0);return`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">Caixa / Vendas</h2><button class="btn btn-outline" onclick="navegar('relatorios')">Ver Relatorios</button></div><div class="grid-2"><div><div class="card"><div class="card-title">Adicionar Produto</div><div class="form-group"><label class="form-label">Produto</label><select class="form-control" id="cx-prod"><option value="">Selecione...</option>${prods.map(p=>`<option value="${p.id}">${p.nome} - ${fmt(p.precoVenda)} (${p.estoqueAtual} un)</option>`).join('')}</select></div><div class="form-row"><div class="form-group"><label class="form-label">Qtd</label><input class="form-control" type="number" id="cx-qtd" min="1" value="1"/></div><div class="form-group"><label class="form-label">Desconto % (max: ${estado.usuario.limiteDesconto}%)</label><input class="form-control" type="number" id="cx-desc" min="0" max="${estado.usuario.limiteDesconto}" value="0"/></div></div><button class="btn btn-primary" style="width:100%" onclick="addItemVenda()">+ Adicionar Item</button></div><div class="card"><div class="card-title">Forma de Pagamento</div><div class="form-row"><div class="form-group"><label class="form-label">Forma</label><select class="form-control" id="cx-pgto"><option>Dinheiro</option><option>PIX</option><option>Cartao Debito</option><option>Cartao Credito</option></select></div><div class="form-group"><label class="form-label">Observacao</label><input class="form-control" id="cx-obs" placeholder="Opcional..."/></div></div></div></div><div><div class="caixa-total"><div class="total-label">Total da Venda</div><div class="total-valor">${fmt(total)}</div><div style="font-size:13px;opacity:.8;margin-top:4px">${estado.vendaAtual.length} item(s) | Vendedor: ${estado.usuario.nome}</div></div><div class="card"><div class="card-title">Itens da Venda</div>${estado.vendaAtual.length===0?'<p style="color:#64748b;font-size:13px;text-align:center;padding:20px">Nenhum item adicionado</p>':estado.vendaAtual.map((it,i)=>`<div class="venda-item"><div class="venda-item-info"><div class="nome">${it.nome}</div><div class="detalhe">${it.qtd}x ${fmt(it.preco)}${it.desconto>0?' | Desc: '+it.desconto+'%':''}</div></div><div class="venda-item-total">${fmt(it.preco*it.qtd*(1-it.desconto/100))}</div><button class="btn btn-danger btn-sm" onclick="removerItem(${i})">X</button></div>`).join('')}${estado.vendaAtual.length>0?`<button class="btn btn-success" style="width:100%;margin-top:12px;padding:12px;font-size:15px" onclick="finalizarVenda()">Finalizar Venda</button><button class="btn btn-outline" style="width:100%;margin-top:8px" onclick="limparVenda()">Cancelar Venda</button>`:''}</div></div></div>`;}
function addItemVenda(){const pid=parseInt(document.getElementById('cx-prod').value);const qtd=parseInt(document.getElementById('cx-qtd').value)||1;const desc=parseFloat(document.getElementById('cx-desc').value)||0;if(!pid){showToast('Selecione um produto','danger');return;}const p=DB.produtos.find(x=>x.id===pid);if(!p)return;const limDesc=estado.usuario.limiteDesconto||0;if(desc>limDesc){showToast(`Desconto maximo: ${limDesc}%`,'danger');return;}if(qtd>p.estoqueAtual){showToast('Quantidade maior que estoque','danger');return;}estado.vendaAtual.push({produtoId:pid,nome:p.nome,preco:p.precoVenda,custo:p.custo,qtd,desconto:desc});renderPagina();}
function removerItem(i){estado.vendaAtual.splice(i,1);renderPagina();}
function limparVenda(){estado.vendaAtual=[];renderPagina();}
function finalizarVenda(){if(estado.vendaAtual.length===0){showToast('Adicione itens','danger');return;}const pgto=document.getElementById('cx-pgto').value;const obs=document.getElementById('cx-obs').value;const total=estado.vendaAtual.reduce((a,i)=>a+(i.preco*i.qtd*(1-i.desconto/100)),0);const venda={id:DB.proximoId.venda++,data:hoje(),usuario:estado.usuario.nome,usuarioId:estado.usuario.id,itens:[...estado.vendaAtual],total,formaPagamento:pgto,observacao:obs};DB.vendas.push(venda);estado.vendaAtual.forEach(it=>{const p=DB.produtos.find(x=>x.id===it.produtoId);if(p)p.estoqueAtual-=it.qtd;});DB.caixa.push({id:DB.proximoId.caixa++,data:hoje(),tipo:'entrada',valor:total,descricao:`Venda #${venda.id}`,formaPagamento:pgto,vendaId:venda.id});salvar();estado.vendaAtual=[];renderPagina();showToast(`Venda #${venda.id} finalizada! Total: ${fmt(total)}`);}
function renderRelatorios(){const vendas=DB.vendas;const totalFat=vendas.reduce((a,v)=>a+v.total,0);const totalCusto=vendas.reduce((a,v)=>a+v.itens.reduce((b,i)=>b+(i.custo*i.qtd),0),0);const lucro=totalFat-totalCusto;const pgtos={};vendas.forEach(v=>{pgtos[v.formaPagamento]=(pgtos[v.formaPagamento]||0)+v.total;});const rankFunc=DB.usuarios.filter(x=>x.ativo).map(usr=>{const vs=vendas.filter(v=>v.usuario===usr.nome);return{nome:usr.nome,perfil:usr.perfil,qtd:vs.length,fat:vs.reduce((a,v)=>a+v.total,0)};}).sort((a,b)=>b.fat-a.fat);return`<div style="margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">Relatorios Gerenciais</h2></div><div class="summary-row"><div class="summary-item"><div class="s-value">${fmt(totalFat)}</div><div class="s-label">Faturamento Total</div></div><div class="summary-item"><div class="s-value">${fmt(totalCusto)}</div><div class="s-label">Custo Total</div></div><div class="summary-item"><div class="s-value" style="color:${lucro>=0?'#16a34a':'#dc2626'}">${fmt(lucro)}</div><div class="s-label">Lucro</div></div><div class="summary-item"><div class="s-value">${vendas.length}</div><div class="s-label">Total Vendas</div></div></div><div class="grid-2"><div class="card"><div class="card-title">🏆 Faturamento por Funcionario</div>${rankFunc.map((r,i)=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid #f1f5f9"><div style="display:flex;align-items:center;gap:8px"><div style="width:24px;height:24px;border-radius:50%;background:${i===0?'#fbbf24':i===1?'#94a3b8':'#d97706'};color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700">${i+1}</div><div><div style="font-weight:600;font-size:13px">${r.nome}</div><div style="font-size:11px;color:#64748b">${r.perfil} | ${r.qtd} venda(s)</div></div></div><strong style="color:#16a34a">${fmt(r.fat)}</strong></div>`).join('')||'<p style="color:#64748b;font-size:13px">Sem dados</p>'}</div><div class="card"><div class="card-title">Forma de Pagamento</div>${Object.entries(pgtos).map(([k,v])=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f1f5f9"><span>${k}</span><strong>${fmt(v)}</strong></div>`).join('')||'<p style="color:#64748b;font-size:13px">Sem dados</p>'}</div></div><div class="card"><div class="card-title">Produtos com Baixo Giro</div><div style="display:flex;flex-wrap:wrap;gap:10px">${DB.produtos.filter(p=>{const v=vendas.reduce((a,venda)=>a+venda.itens.filter(i=>i.produtoId===p.id).reduce((b,i)=>b+i.qtd,0),0);return v<3&&p.ativo;}).map(p=>`<div style="background:#fef3c7;border-radius:8px;padding:8px 12px;font-size:12px"><strong>${p.nome}</strong><br/><span style="color:#d97706">Baixo giro</span></div>`).join('')||'<p style="color:#16a34a;font-size:13px">✅ Todos com boa rotatividade</p>'}</div></div><div class="card"><div class="card-title">Historico de Vendas</div><div class="table-container"><table class="table"><thead><tr><th>#</th><th>Data</th><th>Vendedor</th><th>Itens</th><th>Pagamento</th><th>Total</th></tr></thead><tbody>${vendas.slice().reverse().map(v=>`<tr><td>#${v.id}</td><td>${fmtData(v.data)}</td><td>${v.usuario}</td><td>${v.itens.length}</td><td>${v.formaPagamento}</td><td style="font-weight:700;color:#16a34a">${fmt(v.total)}</td></tr>`).join('')||'<tr><td colspan="6" style="text-align:center;color:#64748b">Sem vendas</td></tr>'}</tbody></table></div></div>`;}
function renderUsuarios(){if(estado.usuario.perfil!=='gestor')return'<p>Acesso negado</p>';return`<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">Gerenciar Usuarios</h2><button class="btn btn-primary" onclick="abrirModalUsuario()">+ Novo Usuario</button></div><div class="card"><div class="table-container"><table class="table"><thead><tr><th>Nome</th><th>Usuario</th><th>Perfil</th><th>Desc. Max</th><th>Vendas</th><th>Faturamento</th><th>Status</th><th>Acoes</th></tr></thead><tbody>${DB.usuarios.map(u=>{const vs=DB.vendas.filter(v=>v.usuario===u.nome);const fat=vs.reduce((a,v)=>a+v.total,0);return`<tr><td><strong>${u.nome}</strong></td><td>${u.usuario}</td><td><span class="badge ${u.perfil==='gestor'?'badge-info':'badge-success'}">${u.perfil}</span></td><td>${u.limiteDesconto}%</td><td>${vs.length}</td><td style="font-weight:600;color:#16a34a">${fmt(fat)}</td><td><span class="badge ${u.ativo?'badge-success':'badge-danger'}">${u.ativo?'Ativo':'Inativo'}</span></td><td><button class="btn btn-outline btn-sm" onclick="editarUsuario(${u.id})" style="margin-right:4px">✏️</button><button class="btn btn-${u.ativo?'danger':'success'} btn-sm" onclick="toggleUsuario(${u.id})">${u.ativo?'Desativar':'Ativar'}</button></td></tr>`;}).join('')}</tbody></table></div></div><div id="modal-usuario" class="modal-overlay"></div>`;}
function abrirModalUsuario(id){const u=id?DB.usuarios.find(x=>x.id===id):null;const m=document.getElementById('modal-usuario');m.innerHTML=`<div class="modal"><div class="modal-header"><h3 class="modal-title">${u?'Editar':'Novo'} Usuario</h3><button class="modal-close" onclick="fecharModal('modal-usuario')">&times;</button></div><div class="form-row"><div class="form-group"><label class="form-label">Nome Completo</label><input class="form-control" id="mu-nome" value="${u?u.nome:''}"/></div><div class="form-group"><label class="form-label">Usuario (login)</label><input class="form-control" id="mu-user" value="${u?u.usuario:''}"/></div></div><div class="form-row"><div class="form-group"><label class="form-label">Senha</label><input class="form-control" type="password" id="mu-senha" placeholder="${u?'Deixe em branco para manter':'Nova senha'}"/></div><div class="form-group"><label class="form-label">Perfil</label><select class="form-control" id="mu-perfil"><option${u&&u.perfil==='gestor'?' selected':''}>gestor</option><option${!u||u.perfil==='funcionario'?' selected':''}>funcionario</option></select></div></div><div class="form-group"><label class="form-label">Limite de Desconto (%)</label><input class="form-control" type="number" id="mu-desc" min="0" max="100" value="${u?u.limiteDesconto:10}"/></div><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn btn-outline" onclick="fecharModal('modal-usuario')">Cancelar</button><button class="btn btn-primary" onclick="salvarUsuario(${u?u.id:'null'})">Salvar</button></div></div>`;m.classList.add('open');}
function salvarUsuario(id){const nome=document.getElementById('mu-nome').value.trim();const usuario=document.getElementById('mu-user').value.trim();const senha=document.getElementById('mu-senha').value;const perfil=document.getElementById('mu-perfil').value;const limiteDesconto=parseInt(document.getElementById('mu-desc').value)||0;if(!nome||!usuario){showToast('Nome e usuario obrigatorios','danger');return;}if(id){const i=DB.usuarios.findIndex(u=>u.id===id);DB.usuarios[i]={...DB.usuarios[i],nome,usuario,perfil,limiteDesconto,...(senha?{senha}:{})};}else{if(!senha){showToast('Senha obrigatoria','danger');return;}DB.usuarios.push({id:DB.proximoId.usuario++,nome,usuario,senha,perfil,limiteDesconto,ativo:true});}salvar();fecharModal('modal-usuario');renderPagina();showToast('Usuario salvo!');}
function editarUsuario(id){abrirModalUsuario(id);}
function toggleUsuario(id){const u=DB.usuarios.find(x=>x.id===id);u.ativo=!u.ativo;salvar();renderPagina();showToast(`Usuario ${u.ativo?'ativado':'desativado'}!`);}
function renderConfiguracoes(){if(estado.usuario.perfil!=='gestor')return'<p>Acesso negado</p>';return`<div style="margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">Configuracoes do Sistema</h2></div><div class="grid-2"><div class="card"><div class="card-title">📊 Resumo</div><p style="font-size:13px;margin-bottom:8px">Produtos: <strong>${DB.produtos.length}</strong></p><p style="font-size:13px;margin-bottom:8px">Usuarios ativos: <strong>${DB.usuarios.filter(u=>u.ativo).length}</strong></p><p style="font-size:13px;margin-bottom:8px">Vendas: <strong>${DB.vendas.length}</strong></p><p style="font-size:13px">Movimentacoes: <strong>${DB.movimentacoes.length}</strong></p></div><div class="card"><div class="card-title">💾 Dados</div><button class="btn btn-danger" style="width:100%;margin-bottom:8px" onclick="if(confirm('Zerar vendas e caixa?')){DB.vendas=[];DB.caixa=[];salvar();renderPagina();showToast('Zerado!')}">Zerar Vendas e Caixa</button><button class="btn btn-outline" style="width:100%" onclick="exportarDados()">Exportar Backup JSON</button></div></div>`;}
function exportarDados(){const blob=new Blob([JSON.stringify(DB,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='stockpro_backup_'+hoje()+'.json';a.click();showToast('Backup exportado!');}
carregar();
function filtrarMarca(v){estado.filtroMarca=v;estado.paginaProduto=1;renderPagina();}
